    private fun initializeTimber() {
        Timber.plant(object : Timber.DebugTree() {
            override fun createStackElementTag(element: StackTraceElement): String {
                return "(${element.fileName}:${element.lineNumber})#${element.methodName}"
            }

            override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                super.log(priority, tag, message, t)
                writeToFile(priority, tag, message, t)
            }
        })

        Timber.plant(FileLoggingTree(context))
    }

    fun logAuthenticationAttempt(
        username: String,
        successful: Boolean,
        method: String = "PASSWORD",
        metadata: Map<String, Any>? = null
    ) {
        val timestamp = dateFormat.format(Date())
        val logData = mutableMapOf<String, Any>(
            "timestamp" to timestamp,
            "event_type" to "AUTHENTICATION_ATTEMPT",
            "username" to username,
            "successful" to successful,
            "auth_method" to method,
            "device_id" to getDeviceId(),
            "app_version" to getAppVersion()
        )

        metadata?.let { logData.putAll(it) }

        val jsonLog = gson.toJson(logData)

        if (successful) {
            Timber.i("AUTH_SUCCESS: %s", jsonLog)
            Log.i("AUTH", "Successful authentication for user: $username via $method")
        } else {
            Timber.w("AUTH_FAILED: %s", jsonLog)
            Log.w("AUTH", "Failed authentication attempt for user: $username via $method")
        }

        writeAuthLog(logData)
    }

    fun logDatabaseQuery(
        query: String,
        parameters: List<Any?>? = null,
        executionTimeMs: Long? = null,
        rowsAffected: Int? = null,
        operation: String = "QUERY"
    ) {
        val timestamp = dateFormat.format(Date())
        val logData = mapOf(
            "timestamp" to timestamp,
            "event_type" to "DATABASE_OPERATION",
            "operation" to operation,
            "query" to query,
            "parameters" to (parameters ?: emptyList()),
            "execution_time_ms" to executionTimeMs,
            "rows_affected" to rowsAffected,
            "thread" to Thread.currentThread().name
        )

        val jsonLog = gson.toJson(logData)

        Timber.v("DB_QUERY: %s", jsonLog)
        Log.v("DATABASE", "Query: $query")
        Log.v("DATABASE", "Parameters: ${parameters?.joinToString(", ")}")
        executionTimeMs?.let { Log.v("DATABASE", "Execution time: ${it}ms") }
        rowsAffected?.let { Log.v("DATABASE", "Rows affected: $it") }

        writeDbLog(logData)
    }

    fun logApiRequest(
        url: String,
        method: String,
        headers: Map<String, String>,
        requestBody: String? = null,
        responseCode: Int? = null,
        responseBody: String? = null,
        durationMs: Long? = null,
        error: Throwable? = null
    ) {
        val timestamp = dateFormat.format(Date())
        
        val sanitizedHeaders = sanitizeHeaders(headers)
        val sanitizedRequestBody = sanitizeBody(requestBody)
        val sanitizedResponseBody = sanitizeBody(responseBody)

        val logData = mutableMapOf<String, Any?>(
            "timestamp" to timestamp,
            "event_type" to "API_REQUEST",
            "url" to url,
            "method" to method,
            "headers" to sanitizedHeaders,
            "request_body" to sanitizedRequestBody,
            "response_code" to responseCode,
            "response_body" to sanitizedResponseBody,
            "duration_ms" to durationMs,
            "thread" to Thread.currentThread().name
        )

        if (error != null) {
            logData["error"] = getStackTraceString(error)
        }

        val jsonLog = gson.toJson(logData)

        val priority = when {
            error != null -> Log.ERROR
            responseCode != null && responseCode >= 400 -> Log.WARN
            else -> Log.DEBUG
        }

        Timber.tag("API").log(priority, "API_REQUEST: %s", jsonLog)
        
        Log.println(priority, "API", "=== API Request ===")
        Log.println(priority, "API", "$method $url")
        Log.println(priority, "API", "Headers: ${gson.toJson(sanitizedHeaders)}")
        requestBody?.let { Log.println(priority, "API", "Request Body: $sanitizedRequestBody") }
        responseCode?.let { Log.println(priority, "API", "Response Code: $it") }
        responseBody?.let { Log.println(priority, "API", "Response Body: $sanitizedResponseBody") }
        durationMs?.let { Log.println(priority, "API", "Duration: ${it}ms") }
        error?.let { 
            Log.println(priority, "API", "Error: ${it.message}")
            Log.println(priority, "API", getStackTraceString(it))
        }

        writeApiLog(logData)
    }

    fun logException(
        throwable: Throwable,
        context: String? = null,
        additionalData: Map<String, Any>? = null,
        fatal: Boolean = false
    ) {
        val timestamp = dateFormat.format(Date())
        val stackTrace = getStackTraceString(throwable)

        val logData = mutableMapOf<String, Any?>(
            "timestamp" to timestamp,
            "event_type" to "EXCEPTION",
            "exception_type" to throwable.javaClass.name,
            "message" to throwable.message,
            "stack_trace" to stackTrace,
            "context" to context,
            "fatal" to fatal,
            "thread" to Thread.currentThread().name,
            "app_version" to getAppVersion(),
            "device_info" to getDeviceInfo()
        )

        additionalData?.let { logData.putAll(it) }

        val jsonLog = gson.toJson(logData)

        if (fatal) {
            Timber.e(throwable, "FATAL_EXCEPTION: %s", jsonLog)
            Log.e("EXCEPTION", "FATAL EXCEPTION in context: $context", throwable)
        } else {
            Timber.e(throwable, "EXCEPTION: %s", jsonLog)
            Log.e("EXCEPTION", "Exception in context: $context", throwable)
        }

        writeExceptionLog(logData)
    }

    fun logUserAction(
        action: String,
        screen: String,
        metadata: Map<String, Any>? = null
