        val jsonLog = gson.toJson(logData)
        Timber.d("USER_ACTION: %s", jsonLog)
        Log.d("USER_ACTION", "Action: $action on screen: $screen")
    }

    fun logPerformanceMetric(
        metricName: String,
        value: Long,
        unit: String = "ms",
        metadata: Map<String, Any>? = null
    ) {
        val timestamp = dateFormat.format(Date())
        val logData = mutableMapOf<String, Any>(
            "timestamp" to timestamp,
            "event_type" to "PERFORMANCE_METRIC",
            "metric_name" to metricName,
