        )

        metadata?.let { logData.putAll(it) }

        val jsonLog = gson.toJson(logData)
        Timber.v("PERFORMANCE: %s", jsonLog)
        Log.v("PERFORMANCE", "$metricName: $value $unit")
    }

    private fun sanitizeHeaders(headers: Map<String, String>): Map<String, String> {
        val sensitiveHeaders = setOf(
            "authorization",
            "x-api-key",
            "cookie",
            "x-auth-token",
            "token"
        )

        return headers.mapValues { (key, value) ->
            if (sensitiveHeaders.contains(key.lowercase())) {
                "[REDACTED]"
            } else {
                value
            }
        }
    }

    private fun sanitizeBody(body: String?): String? {
        if (body == null) return null

        return try {
            val json = JSONObject(body)
            val sensitiveFields = setOf("password", "token", "secret", "apiKey", "creditCard", "ssn")

            sensitiveFields.forEach { field ->
                if (json.has(field)) {
                    json.put(field, "[REDACTED]")
                }
            }
            json.toString()
        } catch (e: Exception) {
            body
        }
    }

    private fun getStackTraceString(throwable: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        throwable.printStackTrace(pw)
        return sw.toString()
    }

    private fun writeToFile(priority: Int, tag: String?, message: String, throwable: Throwable?) {
        try {
            val logDir = File(context.filesDir, "logs")
            if (!logDir.exists()) {
                logDir.mkdirs()
            }

            val dateStr = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(Date())
            val logFile = File(logDir, "log_$dateStr.txt")

            FileWriter(logFile, true).use { writer ->
                val timestamp = dateFormat.format(Date())
                val priorityStr = when (priority) {
                    Log.VERBOSE -> "V"
                    Log.DEBUG -> "D"
                    Log.INFO -> "I"
                    Log.WARN -> "W"
                    Log.ERROR -> "E"
                    Log.ASSERT -> "A"
                    else -> "?"
                }

                writer.append("$timestamp $priorityStr/$tag: $message\n")
                throwable?.let {
                    writer.append(getStackTraceString(it))
                    writer.append("\n")
                }
            }
        } catch (e: Exception) {
            Log.e("LOGGING_SYSTEM", "Failed to write to log file", e)
        }
    }

    private fun writeAuthLog(logData: Map<String, Any>) {
        writeSpecializedLog("auth", logData)
    }

    private fun writeDbLog(logData: Map<String, Any>) {
        writeSpecializedLog("database", logData)
    }

    private fun writeApiLog(logData: Map<String, Any?>) {
        writeSpecializedLog("api", logData)
    }

    private fun writeExceptionLog(logData: Map<String, Any?>) {
        writeSpecializedLog("exceptions", logData)
    }

    private fun writeSpecializedLog(category: String, logData: Map<String, Any?>) {
        try {
            val logDir = File(context.filesDir, "logs/$category")
            if (!logDir.exists()) {
                logDir.mkdirs()
            }

            val dateStr = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(Date())
            val logFile = File(logDir, "${category}_$dateStr.json")

            FileWriter(logFile, true).use { writer ->
                writer.append(gson.toJson(logData))
                writer.append("\n")
            }
        } catch (e: Exception) {
            Log.e("LOGGING_SYSTEM", "Failed to write specialized log", e)
        }
    }

    private fun getDeviceId(): String {
        return android.provider.Settings.Secure.getString(
            context.contentResolver,
            android.provider.Settings.Secure.ANDROID_ID
        )
    }

    private fun getAppVersion(): String {
        return try {
            val packageInfo = context.packageManager.getPackageInfo(context.packageName, 0)
            "${packageInfo.versionName} (${packageInfo.versionCode})"
        } catch (e: Exception) {
            "Unknown"
        }
    }

    private fun getCurrentUserId(): String {
        return "current_user_id"
    }

    private fun getDeviceInfo(): Map<String, String> {
        return mapOf(
            "manufacturer" to android.os.Build.MANUFACTURER,
            "model" to android.os.Build.MODEL,
            "android_version" to android.os.Build.VERSION.RELEASE,
            "sdk_int" to android.os.Build.VERSION.SDK_INT.toString(),
            "device" to android.os.Build.DEVICE,
            "product" to android.os.Build.PRODUCT
        )
    }

    fun getLogFiles(): List<File> {
        val logDir = File(context.filesDir, "logs")
        return logDir.walkTopDown()
            .filter { it.isFile }
            .toList()
    }

    fun clearOldLogs(daysToKeep: Int = 7) {
        val cutoffTime = System.currentTimeMillis() - (daysToKeep * 24 * 60 * 60 * 1000)
        val logDir = File(context.filesDir, "logs")

        logDir.walkTopDown()
            .filter { it.isFile && it.lastModified() < cutoffTime }
            .forEach { file ->
                file.delete()
                Timber.d("Deleted old log file: ${file.name}")
            }
    }

    class FileLoggingTree(private val context: Context) : Timber.Tree() {
        private val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault())

        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            try {
                val logDir = File(context.filesDir, "logs/timber")
                if (!logDir.exists()) {
                    logDir.mkdirs()
                }

                val dateStr = SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(Date())
                val logFile = File(logDir, "timber_$dateStr.txt")

                FileWriter(logFile, true).use { writer ->
                    val timestamp = dateFormat.format(Date())
                    val priorityStr = when (priority) {
                        Log.VERBOSE -> "V"
                        Log.DEBUG -> "D"
                        Log.INFO -> "I"
                        Log.WARN -> "W"
                        Log.ERROR -> "E"
                        Log.ASSERT -> "A"
                        else -> "?"
                    }

                    writer.append("$timestamp $priorityStr/$tag: $message\n")
                    t?.let {
                        val sw = StringWriter()
                        val pw = PrintWriter(sw)
                        it.printStackTrace(pw)
                        writer.append(sw.toString())
                        writer.append("\n")
                    }
                }
            } catch (e: Exception) {
                Log.e("FileLoggingTree", "Error writing to file", e)
            }
        }
    }
