object LoggingManager {
    private lateinit var loggingSystem: ProductionLoggingSystem

    fun initialize(context: Context) {
        loggingSystem = ProductionLoggingSystem(context.applicationContext)
    }

    fun logAuth(username: String, successful: Boolean, method: String = "PASSWORD", metadata: Map<String, Any>? = null) {
        loggingSystem.logAuthenticationAttempt(username, successful, method, metadata)
    }

    fun logDbQuery(query: String, parameters: List<Any?>? = null, executionTimeMs: Long? = null, rowsAffected: Int? = null) {
        loggingSystem.logDatabaseQuery(query, parameters, executionTimeMs, rowsAffected)
    }

    fun logApi(
        url: String,
        method: String,
        headers: Map<String, String>,
        requestBody: String? = null,
        responseCode: Int? = null,
        responseBody: String? = null,
        durationMs: Long? = null,
        error: Throwable? = null
    ) {
        loggingSystem.logApiRequest(url, method, headers, requestBody, responseCode, responseBody, durationMs, error)
    }

    fun logException(throwable: Throwable, context: String? = null, additionalData: Map<String, Any>? = null, fatal: Boolean = false) {
        loggingSystem.logException(throwable, context, additionalData, fatal)
    }

    fun logUserAction(action: String, screen: String, metadata: Map<String, Any>? = null) {
        loggingSystem.logUserAction(action, screen, metadata)
    }

    fun logPerformance(metricName: String, value: Long, unit: String = "ms", metadata: Map<String, Any>? = null) {
        loggingSystem.logPerformanceMetric(metricName, value, unit, metadata)
    }

    fun clearOldLogs(daysToKeep: Int = 7) {
        loggingSystem.clearOldLogs(daysToKeep)
    }

    fun getLogFiles(): List<File> {
        return loggingSystem.getLogFiles()
    }
}

class DatabaseLogger(private val loggingSystem: ProductionLoggingSystem) {
    
    fun <T> logQuery(query: String, parameters: List<Any?>? = null, operation: () -> T): T {
        val startTime = System.currentTimeMillis()
        var rowsAffected: Int? = null
        
        try {
            val result = operation()
            val executionTime = System.currentTimeMillis() - startTime
            
            if (result is Int) {
                rowsAffected = result
            }
            
            loggingSystem.logDatabaseQuery(
                query = query,
                parameters = parameters,
                executionTimeMs = executionTime,
                rowsAffected = rowsAffected,
                operation = "QUERY"
            )
            
            return result
        } catch (e: Exception) {
            val executionTime = System.currentTimeMillis() - startTime
            loggingSystem.logDatabaseQuery(
                query = query,
                parameters = parameters,
                executionTimeMs = executionTime,
                operation = "QUERY_FAILED"
            )
            loggingSystem.logException(e, "Database query failed: $query")
            throw e
        }
    }
}

class ApiLogger(private val loggingSystem: ProductionLoggingSystem) {
    
    fun <T> logRequest(
        url: String,
        method: String,
        headers: Map<String, String>,
        requestBody: String? = null,
        operation: () -> T
    ): T {
        val startTime = System.currentTimeMillis()
        
        try {
            val result = operation()
            val duration = System.currentTimeMillis() - startTime
            
            loggingSystem.logApiRequest(
                url = url,
                method = method,
                headers = headers,
                requestBody = requestBody,
                responseCode = 200,
                durationMs = duration
            )
            
            return result
        } catch (e: Exception) {
            val duration = System.currentTimeMillis() - startTime
            
            loggingSystem.logApiRequest(
                url = url,
                method = method,
                headers = headers,
                requestBody = requestBody,
                durationMs = duration,
                error = e
            )
            
            throw e
        }
    }
}